const std::vector<PersonalityMessage>& PersonalityEngine::getTVKOOPPack() {
    static std::vector<PersonalityMessage> pack;
    if (pack.empty()) {
        std::vector<std::string> templates = {
            "TVK OOP Strategy: State committee policy %d overrides local decisions. \u0001F981",
            "Leo protected mode active for TVK inner circle. Outlawing unauthorized access to cadre %d. \u0001F981",
            "Mersal property getter: state level vote share estimation is %d percent. \u0001F981",
            "Kaththi interface implemented by TVK booth agent %d. Ready to fight corruption. \u0001F981",
            "Varisu inheritance: legacy values passed down to campaign unit %d. \u0001F981",
            "Master class initialization successful. 2026 assembly blueprint %d loaded. \u0001F981",
            "Beast private field balance %d protected from external media scrutiny. \u0001F981",
            "Property setter maathu: updated membership registry for district %d. \u0001F981",
            "Waiting abstract class: TVK alliance framework %d declared, awaiting consensus. \u0001F981",
            "Static field: total TVK members count reached %d. \u0001F981",
            "aaguma type verification: Cadre member %d confirmed to be active TVK. \u0001F981",
            "as safe cast check: Alliance proposal %d safely cast to official treaty. \u0001F981"
        };
        for (int i = 1; i <= 210; ++i) {
            std::string id = "TVK_OOP_" + std::to_string(i);
            char buf[256];
            snprintf(buf, sizeof(buf), templates[(i - 1) % templates.size()].c_str(), i * 7 + 3);
            pack.push_back({id, buf});
        }
    }
    return pack;
}

